import React, { useState, useEffect } from 'react';
import { Box, FormControl, FormLabel, Input, Button, Heading, useToast } from '@chakra-ui/react';
import ReactSelect from 'react-select';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import moment from 'moment';

const QueueTaskTracker = () => {
  const [selectedQueue, setSelectedQueue] = useState(null);
  const [taskId, setTaskId] = useState('');
  const [taskLog, setTaskLog] = useState([]);
  const [startTime, setStartTime] = useState(null);
  const [timeElapsed, setTimeElapsed] = useState(0);
  const [taskInProgress, setTaskInProgress] = useState(false);
  const [timeBeforePause, setTimeBeforePause] = useState(0);
  const [isPaused, setIsPaused] = useState(false);
  const navigate = useNavigate();
  const toast = useToast();

  const queues = [
    'FH Discount Dispute',
    'MP Discount Dispute',
    'FH Pre-service Dispute',
    'MP Pre-service Dispute',
  ];

  // Fetch today's tasks for the logged-in user
  const fetchTodaysTasks = async () => {
    try {
      const response = await axios.get('http://localhost:5000/api/tasks/today', {
        headers: {
          'Authorization': `Bearer ${localStorage.getItem('authToken')}`,
        },
      });

      console.log("Fetched today's tasks:", response.data);
      setTaskLog(response.data);
    } catch (error) {
      console.error("Error fetching today's tasks:", error);

      if (error.response && error.response.status === 401) {
        toast({
          title: 'Session Expired',
          description: 'Your session has expired. Please log in again.',
          status: 'error',
          duration: 3000,
          isClosable: true,
        });

        localStorage.removeItem('authToken');
        navigate('/');
      } else {
        toast({
          title: 'Error',
          description: 'Failed to fetch tasks. Please try again.',
          status: 'error',
          duration: 3000,
          isClosable: true,
        });
      }
    }
  };

  // Fetch tasks for today on component mount
  useEffect(() => {
    fetchTodaysTasks();
  }, [navigate, toast]);

  useEffect(() => {
    let timer;
    if (taskInProgress && !isPaused && startTime) {
      timer = setInterval(() => {
        const seconds = ((Date.now() - startTime) / 1000).toFixed(0);
        setTimeElapsed(formatTimeElapsed(seconds));
      }, 1000);
    } else {
      clearInterval(timer);
    }
    return () => clearInterval(timer);
  }, [taskInProgress, isPaused, startTime]);

  const handleTaskSaveError = (error) => {
    if (error.response && error.response.status === 401) {
      toast({
        title: 'Session Expired',
        description: 'Your session has expired. Please log in again.',
        status: 'error',
        duration: 3000,
        isClosable: true,
      });
  
      localStorage.removeItem('authToken');
      navigate('/');
    } else {
      toast({
        title: 'Error',
        description: 'Failed to save the task. Please try again.',
        status: 'error',
        duration: 3000,
        isClosable: true,
      });
    }
  };
  
  // Format time from seconds to "h m s"
  const formatTimeElapsed = (seconds) => {
    const duration = moment.duration(seconds, 'seconds');
    return `${duration.hours()}h ${duration.minutes()}m ${duration.seconds()}s`;
  };

  const handleQueueChange = (event) => {
    if (event) {
      setSelectedQueue(event);
      setTaskId('');
      setTaskInProgress(false);
      setTimeElapsed(0);
    }
  };

  const handleStartTask = () => {
    if (selectedQueue) {
      setStartTime(Date.now());
      setTaskInProgress(true);
      setIsPaused(false);
      setTimeElapsed(0);
    }
  };

  const handleTaskComplete = async () => {
    if (taskId.trim() && selectedQueue) {
      const endTime = Date.now();
      const totalSeconds = ((endTime - startTime) / 1000).toFixed(0); // Keep `totalSeconds` as a number
  
      const newTask = {
        taskId,
        timeSpent: parseInt(totalSeconds, 10), // Save timeSpent as a number
        queue: selectedQueue.value,
        comment: '',
        isCompleted: true,
      };
  
      try {
        console.log('Attempting to save task:', newTask);
  
        const response = await axios.post('http://localhost:5000/api/tasks', newTask, {
          headers: {
            'Content-Type': 'application/json',
            'Authorization': `Bearer ${localStorage.getItem('authToken')}`, 
          },
        });
  
        console.log('Task saved successfully:', response.data);
  
        // Fetch updated task list to refresh the log
        fetchTodaysTasks();
        setTaskInProgress(false);
        setStartTime(null);
        setTimeElapsed(0);
        setTaskId('');
      } catch (error) {
        console.error('Error saving task:', error);
        handleTaskSaveError(error); // Use the new function to handle the error
      }
    }
  };
  

  const handlePauseResume = () => {
    if (isPaused) {
      setStartTime(Date.now() - timeBeforePause);
      setIsPaused(false);
    } else {
      setTimeBeforePause(Date.now() - startTime);
      setIsPaused(true);
    }
  };

  const handleCommentUpdate = async (taskId, updatedComment) => {
    try {
      console.log("Attempting to update comment for task:", taskId);
      const response = await axios.put(`http://localhost:5000/api/tasks/${taskId}`, 
        { comment: updatedComment }, 
        {
          headers: {
            'Content-Type': 'application/json',
            'Authorization': `Bearer ${localStorage.getItem('authToken')}`, 
          },
        }
      );

      const updatedTask = response.data.task;
      setTaskLog((prevLog) =>
        prevLog.map((task) => (task._id === taskId ? updatedTask : task))
      );

      console.log('Comment updated successfully:', updatedTask);
    } catch (error) {
      console.error("Error updating comment:", error);
      toast({
        title: 'Error',
        description: 'Failed to update the comment. Please try again.',
        status: 'error',
        duration: 3000,
        isClosable: true,
      });
    }
  };

  return (
    <Box maxW={{ base: '100%', md: '66vw' }} mx="auto" mt={10} p={5} borderWidth={1} borderRadius="lg">
      <Heading as="h3" size="lg" mb={4} textAlign="center">
        Task Tracker
      </Heading>

      <FormControl id="queue-selection" mb={4}>
        <FormLabel>Select Queue</FormLabel>
        <ReactSelect
          placeholder="Type Your Queue Name"
          value={selectedQueue}
          onChange={handleQueueChange}
          options={queues.map((queue) => ({ value: queue, label: queue }))}
          isSearchable
        />
      </FormControl>

      {selectedQueue && (
        <>
          <FormControl id="task-id" mb={4}>
            <FormLabel>Enter CSI Call Number</FormLabel>
            <Input
              type="number"
              value={taskId}
              onChange={(e) => setTaskId(e.target.value)}
              placeholder="If this is not a CSI call, enter 0."
            />
          </FormControl>

          {taskInProgress && (
            <Box mt={4} my={6} fontWeight="bold" textAlign="center">
              Time Spent on Current Task: {timeElapsed}
            </Box>
          )}

          {!taskInProgress ? (
            <Button colorScheme="teal" mr={4} onClick={handleStartTask}>
              Start Task
            </Button>
          ) : (
            <Button colorScheme="teal" mr={4} onClick={handleTaskComplete}>
              Finish Task
            </Button>
          )}
          
          <Button colorScheme="teal" onClick={handlePauseResume} isDisabled={!taskInProgress}>
            {isPaused ? 'Resume Timer' : 'Pause Timer'}
          </Button>
        </>
      )}

      <Box my={6} overflowX="auto">
        <Heading as="h4" size="md" mb={4} textAlign="center">
          Task Log
        </Heading>
        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
          <thead>
            <tr>
              <th style={{ border: '1px solid #ccc', padding: '8px', width: '15%' }}>Task ID</th>
              <th style={{ border: '1px solid #ccc', padding: '8px', width: '15%' }}>Queue</th>
              <th style={{ border: '1px solid #ccc', padding: '8px', width: '15%' }}>Time Spent</th>
              <th style={{ border: '1px solid #ccc', padding: '8px', width: '55%' }}>Notes</th>
            </tr>
          </thead>
          <tbody>
            {taskLog.map((task, index) => (
              <tr key={task._id}>
                <td style={{ border: '1px solid #ccc', padding: '8px' }}>{task.taskId}</td>
                <td style={{ border: '1px solid #ccc', padding: '8px' }}>{task.queue}</td>
                <td style={{ border: '1px solid #ccc', padding: '8px' }}>{formatTimeElapsed(task.timeSpent)}</td>
                <td style={{ border: '1px solid #ccc', padding: '8px' }}>
                  <Input
                    type="text"
                    placeholder="Add a comment"
                    value={task.comment || ''}
                    onChange={(e) => {
                      const updatedTaskLog = [...taskLog];
                      updatedTaskLog[index].comment = e.target.value;
                      setTaskLog(updatedTaskLog);
                    }}
                    onBlur={() => handleCommentUpdate(task._id, taskLog[index].comment)}
                  />
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </Box>
    </Box>
  );
};

export default QueueTaskTracker;
